"use client";
import { useState } from "react";
import Header from "@/components/Header";
import Sidebar from "@/components/Sidebar";
import AboutModal from "@/components/AboutModal";

export default function DashboardPage() {
    const [activeTab, setActiveTab] = useState("loans");
    const [showAbout, setShowAbout] = useState(false);

    const loansData = [
        { book: "Мастер и Маргарита", issued: "10.04.2026", due: "10.05.2026", returned: "—", ext: 1, status: "Активна" },
        { book: "Основы JavaScript", issued: "25.03.2026", due: "25.04.2026", returned: "24.04.2026", ext: 0, status: "Возвращена" },
    ];

    const reservationsData = [
        { book: "1984", date: "01.05.2026", pos: 2, expiry: "15.05.2026", status: "Ожидание" },
    ];

    return (
        <>
            <Header onOpenAbout={() => setShowAbout(true)} />

            <div className="container">
                <div className="dashboard-grid">
                    <Sidebar />

                    <main className="main-content">
                        <div className="user-info-card">
                            <div className="avatar large">АК</div>
                            <div>
                                <h3>Анна Ковалёва</h3>
                                <p className="ticket">Билет №2026-0421 • Читатель</p>
                                <span className="verified">Аккаунт верифицирован</span>
                            </div>
                            <div className="extended-stats">
                                <div className="stat-item"><strong>47</strong><span>Всего выдач</span></div>
                                <div className="stat-item"><strong>42</strong><span>Возвращено вовремя</span></div>
                                <div className="stat-item"><strong>2</strong><span>Активных броней</span></div>
                                <div className="stat-item"><strong>0 ₽</strong><span>Задолженность</span></div>
                            </div>
                        </div>

                        <div className="tabs">
                            <button className={`tab ${activeTab === "loans" ? "active" : ""}`} onClick={() => setActiveTab("loans")}>📋 История выдач</button>
                            <button className={`tab ${activeTab === "reservations" ? "active" : ""}`} onClick={() => setActiveTab("reservations")}>📌 Активные бронирования</button>
                            <button className={`tab ${activeTab === "fines" ? "active" : ""}`} onClick={() => setActiveTab("fines")}>⚠️ Штрафы</button>
                            <button className={`tab ${activeTab === "settings" ? "active" : ""}`} onClick={() => setActiveTab("settings")}>⚙️ Настройки</button>
                        </div>

                        {activeTab === "loans" && (
                            <div className="table-wrapper">
                                <table>
                                    <thead>
                                    <tr><th>Книга</th><th>Дата выдачи</th><th>Вернуть до</th><th>Дата возврата</th><th>Продлений</th><th>Статус</th></tr>
                                    </thead>
                                    <tbody>
                                    {loansData.map((row, i) => (
                                        <tr key={i}>
                                            <td>{row.book}</td>
                                            <td>{row.issued}</td>
                                            <td>{row.due}</td>
                                            <td>{row.returned}</td>
                                            <td>{row.ext}</td>
                                            <td><span className={`status ${row.status === "Активна" ? "active" : "returned"}`}>{row.status}</span></td>
                                        </tr>
                                    ))}
                                    </tbody>
                                </table>
                            </div>
                        )}

                        {activeTab === "reservations" && (
                            <div className="table-wrapper">
                                <table>
                                    <thead>
                                    <tr><th>Книга</th><th>Дата бронирования</th><th>Позиция в очереди</th><th>Срок брони</th><th>Статус</th><th>Действия</th></tr>
                                    </thead>
                                    <tbody>
                                    {reservationsData.map((row, i) => (
                                        <tr key={i}>
                                            <td>{row.book}</td>
                                            <td>{row.date}</td>
                                            <td>#{row.pos}</td>
                                            <td>{row.expiry}</td>
                                            <td><span className="status pending">{row.status}</span></td>
                                            <td><button className="btn-reserve">📅 Забронировать</button></td>
                                        </tr>
                                    ))}
                                    </tbody>
                                </table>
                            </div>
                        )}

                        {activeTab === "fines" && (
                            <div className="table-wrapper">
                                <table>
                                    <thead>
                                    <tr><th>Причина</th><th>Сумма</th><th>Дата</th><th>Книга</th><th>Статус</th></tr>
                                    </thead>
                                    <tbody>
                                    <tr><td colSpan="5" className="empty">Задолженность отсутствует</td></tr>
                                    </tbody>
                                </table>
                            </div>
                        )}

                        {activeTab === "settings" && (
                            <form className="settings-form">
                                <h3>Личные данные</h3>
                                <label>
                                    <span>ФИО</span>
                                    <input type="text" defaultValue="Анна Ковалёва" />
                                </label>
                                <label>
                                    <span>Email</span>
                                    <input type="email" defaultValue="anna.k@mail.ru" />
                                </label>
                                <label>
                                    <span>Телефон</span>
                                    <input type="tel" defaultValue="+7 900 123 45 67" />
                                </label>
                                <button type="submit" className="btn-save">Сохранить изменения</button>
                            </form>
                        )}
                    </main>
                </div>
            </div>

            {showAbout && <AboutModal onClose={() => setShowAbout(false)} />}
        </>
    );
}